160	function applyUndoPatch(
161	  current: Record<string, unknown>,
162	  undoPatch: Record<string, unknown>,
163	): Record<string, unknown> {
164	  const restored: Record<string, unknown> = { ...current };
165	  for (const [key, originalValue] of Object.entries(undoPatch)) {
166	    if (originalValue === null) {
167	      delete restored[key];
168	    } else {
