185	export async function executeRevert(
186	  actions: RevertAction[],
187	  dryRun: boolean,
188	  verbose: boolean,
189	  home: string,
190	): Promise<{
191	  succeeded: number;
192	  skipped: number;
193	  failed: Array<{ action: RevertAction; error: string }>;
194	  planned: PlannedChange[];
195	}> {
196	  let succeeded = 0;
197	  let skipped = 0;
198	  const failed: Array<{ action: RevertAction; error: string }> = [];
199	  const planned: PlannedChange[] = [];
200	  const counts = { succeeded, skipped };
201	
202	  for (const action of actions) {
203	    let result: RevertOutcome;
204	    switch (action.kind) {
205	      case "skill-dir":
206	        result = await executeRevertAction(
207	          action,
208	          dryRun,
209	          verbose,
210	          home,
211	          planned,
212	        );
213	        break;
214	      case "file-write":
215	        result = await revertFileWrite(action, dryRun, verbose, home, planned);
216	        break;
217	      case "config-patch":
218	        result = await revertConfigPatch(
219	          action,
220	          dryRun,
221	          verbose,
222	          home,
223	          planned,
224	        );
225	        break;
226	      default:
227	        throw new Error(`Unhandled revert action kind: ${action}`);
228	    }
229	    recordOutcome(result, action, counts, failed);
230	  }
231	
232	  succeeded = counts.succeeded;
233	  skipped = counts.skipped;
