238	async function executeRevertAction(
239	  action: RevertAction,
240	  dryRun: boolean,
241	  verbose: boolean,
242	  home: string,
243	  planned: PlannedChange[],
244	): Promise<RevertOutcome> {
245	  const label = `${action.skill} -> ${action.agent}`;
246	
247	  try {
248	    await lstat(action.target);
249	  } catch (err) {
250	    const result = lstatOutcome(err);
251	    if (result.outcome === "skip") {
252	      logger.skip(label, "(not found, skipping)");
253	      return result;
254	    }
255	    logger.fail(label, result.error);
256	    return result;
257	  }
258	
259	  const entry = await lookupDeployment(home, action.target);
260	  if (!entry || entry.skill !== action.skill || entry.agent !== action.agent) {
261	    logger.warn(
262	      label,
263	      `skipping: ${action.target} is not in the deployment registry — not managed by inception-engine`,
264	    );
265	    return { outcome: "skip" };
266	  }
267	
268	  if (dryRun) {
269	    planned.push({
270	      verb: "remove",
271	      kind: "skill-dir",
272	      skill: action.skill,
273	      agent: action.agent,
274	      target: action.target,
275	    });
276	    return { outcome: "ok" };
277	  }
278	
279	  try {
280	    // Re-stat immediately before deletion to minimise the window between the
281	    // type-check and the removal syscall.
282	    const currentStat = await lstat(action.target);
283	    if (currentStat.isSymbolicLink()) {
284	      await unlink(action.target);
285	    } else {
286	      await rm(action.target, { recursive: true });
287	    }
288	    await unregisterDeployment(home, action.target);
289	    logger.ok(label);
290	    if (verbose) {
291	      logger.detail(`removed: ${action.target}`);
292	    }
293	    return { outcome: "ok" };
294	  } catch (err) {
295	    if ((err as NodeJS.ErrnoException).code === "ENOENT") {
296	      // Target disappeared between ownership check and removal — treat as skip.
297	      logger.skip(label, "(disappeared before removal, skipping)");
298	      return { outcome: "skip" };
299	    }
300	    const msg = err instanceof Error ? err.message : String(err);
301	    logger.fail(label, msg);
302	    return { outcome: "fail", error: msg };
303	  }
304	}
